  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/d/Fiverr/Cannathera/node_modules/.pnpm/@nestjs+cli@11.0.23_@swc+co_9f8535f41a5a6bb7bcf2d38c296c6971/node_modules/@nestjs/cli/node_modules:/mnt/d/Fiverr/Cannathera/node_modules/.pnpm/@nestjs+cli@11.0.23_@swc+co_9f8535f41a5a6bb7bcf2d38c296c6971/node_modules:/mnt/d/Fiverr/Cannathera/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
